WITH p1 AS (
  SELECT 'p1' pid, sku, path, name, properties FROM products
  WHERE brand='Leifheit' AND series='Clean Twist' AND model='Profi 1SY-SM8' AND name LIKE '%Cloth Mop and Wipe%'
), p2 AS (
  SELECT 'p2' pid, sku, path, name, properties FROM products
  WHERE brand='Proxxon' AND series='Professional' AND model='MICRO 2TQ-IHL' AND name LIKE '%Workshop Drill Grinder and Sander%'
), p3 AS (
  SELECT 'p3' pid, sku, path, name, properties FROM products
  WHERE brand='Hammerite' AND series='Direct to Rust' AND model='Direct 2KI-CNL' AND name LIKE '%Metal and Concrete Paint%'
), p4 AS (
  SELECT 'p4' pid, sku, path, name, properties FROM products
  WHERE brand='Gedore' AND series='Heavy Duty' AND model='RED 1HG-ZIH' AND name LIKE '%Hammer Measuring and Cutting Tool%'
), p5 AS (
  SELECT 'p5' pid, sku, path, name, properties FROM products
  WHERE brand='Makita' AND series='LXT' AND model='DUC 1JL-9NJ' AND name LIKE '%Lawn Mower%'
), p6 AS (
  SELECT 'p6' pid, sku, path, name, properties FROM products
  WHERE brand='Wago' AND series='Indoor' AND model='773 2EF-FWX' AND name LIKE '%Extension Cable%'
)
SELECT pid, sku, path, name FROM (
  SELECT * FROM p1 UNION ALL SELECT * FROM p2 UNION ALL SELECT * FROM p3
  UNION ALL SELECT * FROM p4 UNION ALL SELECT * FROM p5 UNION ALL SELECT * FROM p6
) ORDER BY pid, sku LIMIT 200;
